function cloneSeed(value){return JSON.parse(JSON.stringify(value))}
function loadLocalData(){
 const raw=localStorage.getItem('proje360-data');
 if(!raw)return cloneSeed(seed);
 try{const parsed=JSON.parse(raw);return parsed&&typeof parsed==='object'&&!Array.isArray(parsed)?parsed:cloneSeed(seed)}
 catch(error){try{localStorage.setItem('polpro-bozuk-veri-yedegi',raw);localStorage.removeItem('proje360-data')}catch(storageError){}return cloneSeed(seed)}
}
let data=loadLocalData(),currentUser=null;
