data.migrations=data.migrations&&typeof data.migrations==='object'?data.migrations:{};
if(!data.migrations.procurementUserV1){if(!data.categories.includes('Satın Alma'))data.categories.push('Satın Alma');if(!data.users.some(user=>user.email?.toLocaleLowerCase('tr')==='satinalma@polpro.local'))data.users.push({id:Math.max(0,...data.users.map(user=>+user.id||0))+1,name:'Satın Alma Kullanıcısı',email:'satinalma@polpro.local',password:'',category:'Satın Alma',role:'Kullanıcı',active:true});data.migrations.procurementUserV1=true;try{localStorage.setItem('proje360-data',JSON.stringify(data))}catch(error){}}
data.roles=['Yönetici','Kullanıcı','Görüntüleyici'];
window.PolProDirectory={get categories(){return [...data.categories]}};
data.users=data.users.filter(u=>u&&typeof u==='object');data.users.forEach((u,index)=>{u.id??=Date.now()+index;u.name=String(u.name||`Kullanıcı ${index+1}`);u.email=String(u.email||'');u.category=String(u.category||data.categories[0]||'Genel');u.role=data.roles.includes(u.role)?u.role:'Kullanıcı';u.password=String(u.password||'');u.active??=true});
data.projects=data.projects.filter(p=>p&&typeof p==='object');data.projects.forEach((p,index)=>{p.id=Number.isFinite(+p.id)?+p.id:Date.now()+index;p.name=String(p.name||`Proje ${index+1}`);p.client=String(p.client||'');p.start=p.start||new Date().toISOString().slice(0,10);p.end=p.end||p.start;p.budget=Number(p.budget)||0;const previousLeaders=Array.isArray(p.managers)?p.managers.filter(Boolean):[];p.manager=String(p.manager||previousLeaders[0]||'');p.managers=p.manager?[p.manager]:[];p.team=Array.isArray(p.team)?p.team.filter(Boolean):[]});
data.tasks=data.tasks.filter(t=>t&&typeof t==='object');data.tasks.forEach((t,index)=>{t.id=Number.isFinite(+t.id)?+t.id:Date.now()+1000+index;t.projectId=+t.projectId;t.title=String(t.title||`Görev ${index+1}`);t.assignee=String(t.assignee||'Atanmadı');if(!['user','unit'].includes(t.assigneeType))t.assigneeType=data.projects.some(p=>p.id===t.projectId&&p.client===t.assignee)?'unit':'user';t.status=['todo','doing','done'].includes(t.status)?t.status:'todo';t.priority=String(t.priority||'Orta');t.end=t.end||t.due||new Date().toISOString().slice(0,10);const d=new Date(t.end+'T12:00:00');d.setDate(d.getDate()-3);t.start=t.start||d.toISOString().slice(0,10);delete t.due});
data.costs=data.costs.filter(c=>c&&typeof c==='object');data.costs.forEach((c,index)=>{c.id=Number.isFinite(+c.id)?+c.id:Date.now()+2000+index;c.projectId=c.projectId?+c.projectId:null;c.date=c.date||new Date().toISOString().slice(0,10);c.description=String(c.description||'Maliyet kaydı');c.category=String(c.category||'Diğer');c.costType=['Direkt İşçilik','Endirekt İşçilik','İşçilik Dışı'].includes(c.costType)?c.costType:(c.category==='Endirekt İşçilik'?'Endirekt İşçilik':['İşçilik','Direkt İşçilik'].includes(c.category)?'Direkt İşçilik':'İşçilik Dışı');if(c.costType==='Direkt İşçilik')c.category='Direkt İşçilik';if(c.costType==='Endirekt İşçilik')c.category='Endirekt İşçilik';c.vendor=String(c.vendor||'');c.amount=Number(c.amount)||0});
data.activities=data.activities.filter(a=>a&&typeof a==='object');data.files=data.files.filter(f=>f&&typeof f==='object');data.suppliers=data.suppliers.filter(s=>s&&typeof s==='object');data.suppliers.forEach(s=>{const legacyGroups={Ekipman:'Makine / Ekipman',Malzeme:'Hammadde / Malzeme',İşçilik:'Montaj / Saha Hizmeti',Hizmet:'Danışmanlık / Mühendislik',Yazılım:'Otomasyon / Yazılım',Diğer:'Diğer'};s.name=String(s.name||'Tedarikçi');s.supplierGroup=String(s.supplierGroup||legacyGroups[s.category]||s.category||'Diğer');s.category=s.supplierGroup;s.workDescription=String(s.workDescription||'');s.rating=Math.max(0,Math.min(5,Number(s.rating)||0));s.reviewNote=String(s.reviewNote||'');s.evaluatedAt=String(s.evaluatedAt||'');s.evaluatedBy=String(s.evaluatedBy||'')});data.files.forEach(f=>{f.projectId=+f.projectId;f.taskId=f.taskId?+f.taskId:null;f.name=String(f.name||'Dosya');f.type=String(f.type||'application/octet-stream')});
const obsoleteRecoveredIds=new Set(data.projects.filter(project=>(+project.id===9001&&project.name==='Roketsan Test Ünitesi')||(+project.id===9002&&project.name==='Malaksör Projesi')).map(project=>+project.id));
if(obsoleteRecoveredIds.size){data.projects=data.projects.filter(project=>!obsoleteRecoveredIds.has(+project.id));['tasks','costs','activities','files','suppliers','procurements','manufacturings','risks','issues','changes','actions','documents','qualityRecords','closures'].forEach(key=>{if(Array.isArray(data[key]))data[key]=data[key].filter(record=>!obsoleteRecoveredIds.has(+record.projectId))});try{localStorage.setItem('proje360-data',JSON.stringify(data))}catch(error){}}
const projectPalette=['#2f3234','#4b4f51','#686c6e','#85898a'];data.projects.forEach((p,i)=>p.color=projectPalette[i%projectPalette.length]);
const costCategories=['Direkt İşçilik','Endirekt İşçilik','Araç Kiralama','Akaryakıt','Otel / Konaklama','Danışmanlık','Seyahat / Ulaşım','Yemek / Temsil','Kargo / Lojistik','Ofis Gideri','Bakım / Servis','Ekipman','Malzeme','Hizmet','Yazılım','Vergi / Harç','Diğer'];
const $=s=>document.querySelector(s), $$=s=>document.querySelectorAll(s);
const fxRates={TRY:1,EUR:53.7039,USD:53.7039/1.1430};let displayCurrency=localStorage.getItem('proje360-currency')||'TRY';
const money=n=>new Intl.NumberFormat('tr-TR',{style:'currency',currency:displayCurrency,maximumFractionDigits:displayCurrency==='TRY'?0:2}).format((Number(n)||0)/fxRates[displayCurrency]);
const fromBaseCurrency=n=>(Number(n)||0)/fxRates[displayCurrency];
const toBaseCurrency=n=>(Number(n)||0)*fxRates[displayCurrency];
const date=s=>new Intl.DateTimeFormat('tr-TR',{day:'numeric',month:'short',year:'numeric'}).format(new Date(s+'T12:00:00'));
const compactDateRange=(start,end)=>{const a=new Date(start+'T12:00:00'),b=new Date(end+'T12:00:00'),day=n=>n.toLocaleDateString('tr-TR',{day:'numeric'}),month=n=>n.toLocaleDateString('tr-TR',{month:'short'});return a.getFullYear()===b.getFullYear()&&a.getMonth()===b.getMonth()?`${day(a)}–${day(b)} ${month(b)} ${b.getFullYear()}`:a.getFullYear()===b.getFullYear()?`${day(a)} ${month(a)} – ${day(b)} ${month(b)} ${b.getFullYear()}`:`${date(start)} – ${date(end)}`};
const project=id=>data.projects.find(p=>p.id===+id);
const managerNames=p=>String(p.manager||p.managers?.[0]||'Atanmadı');
const spent=id=>data.costs.filter(c=>c.projectId===+id).reduce((a,c)=>a+c.amount,0);
const progress=id=>{const p=project(id);if(p&&p.completion!==''&&p.completion!=null&&Number.isFinite(+p.completion))return Math.max(0,Math.min(100,Math.round(+p.completion)));const t=data.tasks.filter(x=>x.projectId===+id);return t.length?Math.round(t.reduce((sum,task)=>sum+(task.completion!==''&&task.completion!=null?Math.max(0,Math.min(100,+task.completion||0)):task.status==='done'?100:task.status==='doing'?50:0),0)/t.length):0};
const taskFiles=id=>data.files.filter(f=>+f.taskId===+id);
const taskAssigneeLabel=t=>`${t?.assigneeType==='unit'?'Birim · ':''}${t?.assignee||'Atanmadı'}`;
const taskAssigneeInitials=t=>t?.assigneeType==='unit'?'BR':String(t?.assignee||'?').split(' ').map(x=>x[0]).slice(0,2).join('');
function save(){data.tasks.forEach(task=>{if(task.status==='done')task.completion=100;else if(task.status==='todo'&&+task.completion===100)task.completion=0});const taskIds=new Set(data.tasks.map(task=>+task.id)),projectIds=new Set(data.projects.map(record=>+record.id));data.files=data.files.filter(file=>(!file.taskId||taskIds.has(+file.taskId))&&projectIds.has(+file.projectId));['procurements','manufacturings','risks','issues','changes','actions','documents','qualityRecords','closures'].forEach(key=>{if(data[key])data[key]=data[key].filter(record=>projectIds.has(+record.projectId))});localStorage.setItem('proje360-data',JSON.stringify(data));if(window.PolProCloud?.enabled)void window.PolProCloud.save(data);renderAll();applyPermissions()}
function renderAll(){renderMetrics();renderProjects();renderTasks();renderCosts();renderPlanning();renderDashboardGantt();renderAdmin();fillProjects();decorateEditable();bindProjectCards()}
let dashboardFilterId=0;
function renderMetrics(){
 const projects=dashboardFilterId?data.projects.filter(p=>p.id===dashboardFilterId):data.projects,ids=new Set(projects.map(p=>p.id)),tasks=data.tasks.filter(t=>ids.has(t.projectId)),costs=data.costs.filter(c=>ids.has(c.projectId)),today=new Date();today.setHours(0,0,0,0);const totalBudget=projects.reduce((a,p)=>a+p.budget,0),totalSpent=costs.reduce((a,c)=>a+c.amount,0),open=tasks.filter(t=>t.status!=='done').length,late=tasks.filter(t=>t.status!=='done'&&new Date(t.end+'T23:59:59')<today).length,overBudget=projects.filter(p=>spent(p.id)>p.budget).length,avg=projects.length?Math.round(projects.reduce((a,p)=>a+progress(p.id),0)/projects.length):0;
 $('#metrics').innerHTML=[['Aktif proje',projects.length,overBudget?`${overBudget} bütçe aşımı`:'Bütçeler normal',''],['Toplam bütçe',money(totalBudget),'Planlanan','budget-good'],['Gerçekleşen gider',money(totalSpent),totalBudget?Math.round(totalSpent/totalBudget*100)+'% kullanıldı':'—','expense-bad'],['Açık görev',open,late?`${late} geciken görev`:avg+'% ort. ilerleme',late?'warning-metric':'']].map((x,i)=>`<article class="metric ${x[3]}"><div class="metric-icon m${i}">${['▦','₺','◔','✓'][i]}</div><div><span>${x[0]}</span><strong>${x[1]}</strong><small>${x[2]}</small></div></article>`).join('');
 $('#projectOverview').innerHTML=data.projects.map(p=>{const pc=progress(p.id),s=spent(p.id),over=s>p.budget,delayed=pc<100&&new Date(p.end+'T23:59:59')<today;return `<div class="overview-row dashboard-project ${dashboardFilterId===p.id?'selected':''} ${over||delayed?'has-warning':''}" data-dashboard-project="${p.id}"><div class="project-mark" style="background:${p.color}">${p.name[0]}</div><div class="overview-name"><strong>${p.name}${over?' <em class="warning-badge">Bütçe aşıldı</em>':''}${delayed?' <em class="warning-badge late-badge">Gecikti</em>':''}</strong><small>${managerNames(p)} · ${date(p.end)}</small></div><div class="progress-cell"><div><span>İlerleme</span><b>${pc}%</b></div><div class="bar"><i style="width:${pc}%;background:${delayed?'var(--red)':p.color}"></i></div></div><div class="budget-cell"><strong class="expense-text">${money(s)}</strong><small class="budget-text">/ ${money(p.budget)}</small></div></div>`}).join('');
 const groups=Object.entries(costs.reduce((a,c)=>(a[c.category]=(a[c.category]||0)+c.amount,a),{})).sort((a,b)=>b[1]-a[1]),total=costs.reduce((a,c)=>a+c.amount,0);$('#costChart').innerHTML=`<div class="donut ${total>totalBudget?'over-budget':''}" style="--pct:${totalBudget?Math.min(100,Math.round(total/totalBudget*100)):0}"><div><strong class="expense-text">${money(total)}</strong><small>Toplam gider</small></div></div><div class="legend">${groups.map(([k,v],i)=>`<div><i class="c${i%4}"></i><span>${k}</span><b class="expense-text">${money(v)}</b></div>`).join('')}</div>`;
 $('#upcomingTasks').innerHTML=tasks.filter(t=>t.status!=='done').sort((a,b)=>a.end.localeCompare(b.end)).slice(0,4).map(t=>taskRow(t)).join('')||empty('Açık görev yok.');
 $('#recentCosts').innerHTML=costs.sort((a,b)=>b.date.localeCompare(a.date)).slice(0,4).map(c=>`<div class="recent"><div class="cost-icon">₺</div><div><strong>${c.description}</strong><small>${project(c.projectId)?.name}</small></div><b class="expense-text">${money(c.amount)}</b></div>`).join('')||empty('Gider kaydı yok.');
 const filter=$('#dashboardProjectFilter');filter.innerHTML='<option value="">Tüm projeler</option>'+data.projects.map(p=>`<option value="${p.id}">${p.name}</option>`).join('');filter.value=dashboardFilterId||'';filter.onchange=()=>setDashboardFilter(+filter.value);$$('[data-dashboard-project]').forEach(row=>row.onclick=()=>setDashboardFilter(+row.dataset.dashboardProject));
}
function setDashboardFilter(id){dashboardFilterId=id||0;renderMetrics();renderDashboardGantt();toast(id?`${project(id)?.name} filtresi uygulandı.`:'Tüm projeler gösteriliyor.')}
function renderProjects(){$('#projectGrid').innerHTML=data.projects.map(p=>{const pc=progress(p.id),s=spent(p.id),ratio=p.budget>0?Math.round(s/p.budget*100):0,over=p.budget>0&&s>p.budget,late=pc<100&&new Date(p.end+'T23:59:59')<new Date();return `<article class="project-card ${over?'over-budget-card':''} ${late?'late-project-card':''}"><div class="project-card-cover">${p.image?`<img src="${p.image}" alt="${p.name} proje görseli">`:`<div class="project-cover-placeholder" style="background:${p.color}"><span>${p.name[0]}</span><small>POLPRO</small></div>`}</div><div class="project-top"><div class="project-logo" style="background:${p.color}">${p.name[0]}</div><div class="card-alerts">${over?'<em class="warning-badge">Bütçe aşıldı</em>':''}${late?'<em class="warning-badge late-badge">Termin geçti</em>':''}</div><button class="delete" data-delete-project="${p.id}" title="Sil">×</button></div><span class="project-client">${p.client}</span><h3>${p.name}</h3><p class="manager">${managerNames(p)} · ${date(p.end)} bitiş</p><div class="project-stat"><span>İlerleme</span><b>${pc}%</b></div><div class="bar"><i style="width:${pc}%;background:${late?'var(--red)':p.color}"></i></div><div class="project-budget"><div><small>Bütçe</small><strong class="budget-text">${money(p.budget)}</strong></div><div><small>Gider</small><strong class="expense-text">${money(s)}</strong></div></div><div class="budget-bar"><i style="width:${Math.min(ratio,100)}%" class="${over?'over':''}"></i></div></article>`}).join('')||empty('Henüz proje yok.');bindDeletes()}
function taskRow(t){const late=t.status!=='done'&&new Date(t.end+'T23:59:59')<new Date(),fileCount=taskFiles(t.id).length;return `<div class="task-row ${late?'late-task':''}"><span class="priority ${t.priority.toLowerCase().replace('ü','u').replace('ş','s')}" title="${t.priority}"></span><div><strong>${t.title}${late?' <em class="warning-badge late-badge">Gecikti</em>':''}</strong><small>${project(t.projectId)?.name} · ${taskAssigneeLabel(t)}${fileCount?` · 📎 ${fileCount} belge`:''}</small></div><span class="assignee" title="${taskAssigneeLabel(t)}">${taskAssigneeInitials(t)}</span><time>${compactDateRange(t.start,t.end)}</time></div>`}
function renderTasks(){const cols=[['todo','Yapılacak'],['doing','Devam ediyor'],['done','Tamamlandı']];$('#kanban').innerHTML=cols.map(([key,label])=>`<div class="kanban-col"><div class="kanban-head"><h3>${label}</h3><span>${data.tasks.filter(t=>t.status===key).length}</span></div><div>${data.tasks.filter(t=>t.status===key).map(t=>{const fileCount=taskFiles(t.id).length;return `<article class="task-card"><div class="task-card-top"><span class="tag">${project(t.projectId)?.name}</span><button class="delete" data-delete-task="${t.id}">×</button></div><h4>${t.title}</h4><div class="task-meta"><span class="priority-text ${t.priority.toLowerCase().replace('ü','u').replace('ş','s')}">${t.priority}</span><time>${date(t.start)} – ${date(t.end)}</time></div>${fileCount?`<button class="task-file-count" data-record-edit="task:${t.id}" title="Görev belgelerini aç">📎 ${fileCount} belge</button>`:''}<div class="task-foot"><span class="assignee">${t.assignee.split(' ').map(x=>x[0]).join('')}</span><select data-status="${t.id}"><option value="todo" ${key==='todo'?'selected':''}>Yapılacak</option><option value="doing" ${key==='doing'?'selected':''}>Devam ediyor</option><option value="done" ${key==='done'?'selected':''}>Tamamlandı</option></select></div></article>`}).join('')||empty('Görev yok')}</div></div>`).join('');$$('[data-status]').forEach(s=>s.onchange=()=>{const t=data.tasks.find(t=>t.id===+s.dataset.status);t.status=s.value;addActivity(t.projectId,'Görev durumu değiştirildi',`${t.title} — ${s.options[s.selectedIndex].text}`,'task');save()});bindDeletes()}
function renderCosts(){const budget=data.projects.reduce((a,p)=>a+p.budget,0),projectCosts=data.costs.filter(c=>c.projectId),directLabor=projectCosts.filter(c=>c.costType==='Direkt İşçilik').reduce((a,c)=>a+c.amount,0),indirectLabor=projectCosts.filter(c=>c.costType==='Endirekt İşçilik').reduce((a,c)=>a+c.amount,0),nonLabor=projectCosts.filter(c=>c.costType==='İşçilik Dışı').reduce((a,c)=>a+c.amount,0),externalTotal=data.costs.filter(c=>!c.projectId).reduce((a,c)=>a+c.amount,0),grandTotal=data.costs.reduce((a,c)=>a+c.amount,0);$('#costSummary').innerHTML=`<article class="budget-good"><span>Proje bütçeleri</span><strong class="budget-text">${money(budget)}</strong></article><article class="direct-labor-summary"><span>Direkt işçilik</span><strong>${money(directLabor)}</strong></article><article class="indirect-labor-summary"><span>Endirekt işçilik</span><strong>${money(indirectLabor)}</strong></article><article><span>İşçilik dışı giderler</span><strong class="expense-text">${money(nonLabor)}</strong></article><article class="external-cost-summary"><span>Proje dışı giderler</span><strong class="expense-text">${money(externalTotal)}</strong></article><article><span>Toplam gider</span><strong class="expense-text">${money(grandTotal)}</strong></article>`;filterCosts()}
function renderPlanning(){renderGantt();renderWorkload()}
function renderGantt(){
 const range=$('#ganttRange')?.value||'fit',allDates=[...data.projects.flatMap(p=>[p.start,p.end]),...data.tasks.flatMap(t=>[t.start,t.end])].filter(value=>/^\d{4}-\d{2}-\d{2}$/.test(value)).sort(),today=new Date();today.setHours(12,0,0,0);let start,end;
 if(range==='fit'&&allDates.length){start=new Date(allDates[0]+'T12:00:00');end=new Date(allDates.at(-1)+'T12:00:00');start.setDate(start.getDate()-14);end.setDate(end.getDate()+14)}else{const days=Math.max(90,+range||180);start=new Date(today);start.setDate(start.getDate()-14);end=new Date(start);end.setDate(end.getDate()+days)}
 if(end<=start)end=new Date(start.getTime()+86400000);const total=end-start,monthSpan=Math.max(1,(end.getFullYear()-start.getFullYear())*12+end.getMonth()-start.getMonth()+1),timelineWidth=Math.max(850,265+monthSpan*105);
 const months=[];let cursor=new Date(start.getFullYear(),start.getMonth(),1);while(cursor<end){const next=new Date(cursor.getFullYear(),cursor.getMonth()+1,1),left=Math.max(0,(cursor-start)/total*100),right=Math.min(100,(next-start)/total*100);months.push(`<span style="left:${left}%;width:${Math.max(0,right-left)}%">${cursor.toLocaleDateString('tr-TR',{month:'short',year:'2-digit'})}</span>`);cursor=next}
 const pos=d=>Math.max(0,Math.min(100,(new Date(d+'T12:00:00')-start)/total*100)),todayInRange=today>=start&&today<=end,todayPos=(today-start)/total*100,todayLine=todayInRange?`<i class="today-line" style="left:${todayPos}%"></i>`:'';let rows='';
 data.projects.forEach(p=>{const left=pos(p.start),right=pos(p.end);rows+=`<div class="gantt-row project-row" data-project-id="${p.id}"><div class="gantt-label"><strong>${p.name}</strong><small>${date(p.start)} – ${date(p.end)}</small></div><div class="gantt-track">${todayLine}<span class="gantt-bar project-bar" style="left:${left}%;width:${Math.max(.35,right-left)}%;background:${p.color}"><b>${progress(p.id)}%</b></span></div></div>`;data.tasks.filter(t=>t.projectId===p.id).sort((a,b)=>a.start.localeCompare(b.start)).forEach(t=>{const left=pos(t.start),right=pos(t.end),late=t.status!=='done'&&new Date(t.end+'T23:59:59')<today;rows+=`<div class="gantt-row task-gantt-row" data-project-id="${p.id}"><div class="gantt-label"><span>${t.title}</span><small>${t.assignee} · ${date(t.start)} – ${date(t.end)}</small></div><div class="gantt-track">${todayLine}<span class="gantt-bar task-range ${late?'late':''}" data-gantt-task="${t.id}" style="left:${left}%;width:${Math.max(.35,right-left)}%" title="Düzenle: ${t.title}"><b class="task-person">${t.assignee}</b></span></div></div>`})});
 const gantt=$('#gantt');gantt.style.width=`${timelineWidth}px`;gantt.innerHTML=`<div class="gantt-head"><div>Proje / görev</div><div class="month-track">${months.join('')}${todayLine}</div></div>${rows||empty('Planlanmış kayıt yok.')}`;bindGanttTaskEditing(gantt)
}
function renderDashboardGantt(){const target=$('#dashboardGantt'),source=$('#gantt');if(target&&source){target.innerHTML=`<div class="gantt" style="width:${source.style.width||'850px'}">${source.innerHTML}</div>`;if(dashboardFilterId)target.querySelectorAll('.gantt-row').forEach(row=>row.hidden=+row.dataset.projectId!==dashboardFilterId);target.scrollLeft=0;bindGanttTaskEditing(target)}}
function bindGanttTaskEditing(root){root?.querySelectorAll('.task-range').forEach(bar=>{if(!bar.dataset.ganttTask){const title=bar.closest('.gantt-row')?.querySelector('.gantt-label span')?.textContent,task=data.tasks.find(t=>t.projectId===currentDetailId&&t.title===title);if(task)bar.dataset.ganttTask=task.id}if(bar.dataset.ganttTask)bar.onclick=e=>{e.stopPropagation();openDialog('task',bar.dataset.ganttTask)}})}
function renderWorkload(){const today=new Date();today.setHours(0,0,0,0),people=[...new Set(data.tasks.map(t=>t.assignee))].sort();const open=data.tasks.filter(t=>t.status!=='done'),late=open.filter(t=>new Date(t.end+'T23:59:59')<today),week=new Date(today);week.setDate(week.getDate()+7);const soon=open.filter(t=>{const d=new Date(t.end+'T12:00:00');return d>=today&&d<=week});$('#workloadMetrics').innerHTML=`<article><span>Ekip üyesi</span><strong>${people.length}</strong></article><article><span>Açık görev</span><strong>${open.length}</strong></article><article><span>Geciken görev</span><strong class="danger">${late.length}</strong></article><article><span>7 gün içinde</span><strong>${soon.length}</strong></article>`;$('#workloadGrid').innerHTML=people.map(name=>{const tasks=data.tasks.filter(t=>t.assignee===name),active=tasks.filter(t=>t.status!=='done'),done=tasks.filter(t=>t.status==='done').length,overdue=active.filter(t=>new Date(t.end+'T23:59:59')<today).length,load=Math.min(100,active.length*20);return `<article class="person-card"><div class="person-head"><span class="person-avatar">${name.split(' ').map(x=>x[0]).join('')}</span><div><h3>${name}</h3><p>${active.length} açık · ${done} tamamlandı</p></div><span class="load-badge ${active.length>4?'busy':''}">${active.length>4?'Yoğun':active.length>2?'Dengeli':'Uygun'}</span></div><div class="load-label"><span>İş yükü</span><b>%${load}</b></div><div class="bar load-bar"><i style="width:${load}%"></i></div>${overdue?`<p class="overdue">⚠ ${overdue} geciken görev</p>`:''}<div class="person-tasks">${active.sort((a,b)=>a.end.localeCompare(b.end)).map(t=>`<div><span class="priority ${t.priority.toLowerCase().replace('ü','u').replace('ş','s')}"></span><p><strong>${t.title}</strong><small>${project(t.projectId)?.name}</small></p><time class="${new Date(t.end+'T23:59:59')<today?'danger':''}">${date(t.start)} – ${date(t.end)}</time></div>`).join('')||'<div class="all-done">Tüm görevler tamamlandı ✓</div>'}</div></article>`}).join('')||empty('Henüz ekip üyesi yok.')}
function renderAdmin(){const active=data.users.filter(u=>u.active).length,inactive=data.users.length-active;$('#userStats').innerHTML=`<article><span>Toplam personel</span><strong>${data.users.length}</strong></article><article><span>Aktif personel</span><strong>${active}</strong></article><article><span>Pasif personel</span><strong>${inactive}</strong></article><article><span>Kategori</span><strong>${data.categories.length}</strong></article>`;$('#userGrid').innerHTML=data.users.map(u=>`<article class="user-card"><div class="user-card-head"><span class="person-avatar">${u.name.split(' ').map(x=>x[0]).join('')}</span><span class="user-state ${u.active?'':'inactive'}">${u.active?'Aktif':'Pasif'}</span></div><h3>${u.name}</h3><p>${u.email||'Giriş hesabı gerektirmez'}</p><div class="user-details"><span>${u.category}</span><b>${u.role}</b></div><div class="user-actions"><button class="secondary" data-edit-user="${u.id}">Düzenle</button><button class="delete" data-delete-user="${u.id}">×</button></div></article>`).join('');$('#categoryList').innerHTML=data.categories.map((x,i)=>`<div><span>${x}</span><b>${data.users.filter(u=>u.category===x).length} personel</b><button class="edit" data-rename-category="${i}">✎</button><button class="delete" data-delete-category="${i}">×</button></div>`).join('');$$('[data-edit-user]').forEach(b=>b.onclick=()=>openDialog('user',b.dataset.editUser));$$('[data-delete-user]').forEach(b=>b.onclick=()=>{if(confirm('Personel kaydı silinsin mi? Görevlerdeki eski atama adları korunur.')){data.users=data.users.filter(u=>u.id!==+b.dataset.deleteUser);save()}});bindNamedSettings();window.PolProAccounts?.refresh?.()}
function bindNamedSettings(){$$('[data-rename-category]').forEach(b=>b.onclick=()=>renameSetting('categories',+b.dataset.renameCategory));$$('[data-rename-role]').forEach(b=>b.onclick=()=>renameSetting('roles',+b.dataset.renameRole));$$('[data-delete-category]').forEach(b=>b.onclick=()=>deleteSetting('categories',+b.dataset.deleteCategory));$$('[data-delete-role]').forEach(b=>b.onclick=()=>deleteSetting('roles',+b.dataset.deleteRole))}
function renameSetting(type,index){const old=data[type][index],name=prompt('Yeni ad',old)?.trim();if(!name||name===old)return;data[type][index]=name;data.users.forEach(u=>{if(type==='categories'&&u.category===old)u.category=name;if(type==='roles'&&u.role===old)u.role=name});save()}
function deleteSetting(type,index){const value=data[type][index],used=data.users.some(u=>(type==='categories'?u.category:u.role)===value);if(used)return toast('Önce bağlı kullanıcıları başka bir seçeneğe taşıyın.');if(confirm(`“${value}” silinsin mi?`)){data[type].splice(index,1);save()}}
function decorateEditable(){$$('.project-card').forEach((el,i)=>{const box=el.querySelector('.project-top');if(box&&!box.querySelector('.edit'))box.insertAdjacentHTML('beforeend',`<button class="edit floating-edit" data-record-edit="project:${data.projects[i].id}">✎</button>`)});$$('.task-card').forEach(el=>{const del=el.querySelector('[data-delete-task]');if(del&&!el.querySelector('.edit'))del.insertAdjacentHTML('beforebegin',`<button class="edit" data-record-edit="task:${del.dataset.deleteTask}">✎</button>`)});$$('#costTable tr').forEach(el=>{const del=el.querySelector('[data-delete-cost]');if(del&&!el.querySelector('.edit'))del.insertAdjacentHTML('beforebegin',`<button class="edit" data-record-edit="cost:${del.dataset.deleteCost}">✎</button>`)});$$('[data-record-edit]').forEach(b=>b.onclick=()=>{const [type,id]=b.dataset.recordEdit.split(':');openDialog(type,id)})}
function filterCosts(){const q=$('#costSearch').value.toLocaleLowerCase('tr'),pid=$('#costProjectFilter').value,category=$('#costCategoryFilter')?.value||'',costType=$('#costTypeFilter')?.value||'';const rows=data.costs.filter(c=>{const scopeMatch=!pid||(pid==='external'?!c.projectId:c.projectId===+pid),categoryMatch=!category||c.category===category,typeMatch=!costType||c.costType===costType,searchText=`${c.description} ${c.vendor||''} ${c.category} ${c.costType} ${c.projectId?project(c.projectId)?.name||'':'proje dışı genel gider'}`.toLocaleLowerCase('tr');return scopeMatch&&categoryMatch&&typeMatch&&searchText.includes(q)});$('#costTable').innerHTML=rows.sort((a,b)=>b.date.localeCompare(a.date)).map(c=>`<tr><td>${date(c.date)}</td><td><strong>${c.description}</strong></td><td>${c.projectId?project(c.projectId)?.name||'Silinmiş proje':'<span class="cost-scope external">Proje dışı / Genel gider</span>'}</td><td><span class="category">${c.category}</span></td><td><span class="cost-type ${c.costType==='Direkt İşçilik'?'direct-labor':c.costType==='Endirekt İşçilik'?'indirect-labor':'non-labor'}">${c.costType}</span></td><td>${c.vendor||'—'}</td><td class="right"><strong class="expense-text">${money(c.amount)}</strong></td><td><button class="delete" data-delete-cost="${c.id}">×</button></td></tr>`).join('')||`<tr><td colspan="8">${empty('Kayıt bulunamadı.')}</td></tr>`;bindDeletes();decorateEditable();applyPermissions()}
function fillProjects(){const projectFilter=$('#costProjectFilter'),selected=projectFilter.value;projectFilter.innerHTML='<option value="">Tüm maliyetler</option><option value="external">Proje dışı / Genel gider</option>'+data.projects.map(p=>`<option value="${p.id}">${p.name}</option>`).join('');projectFilter.value=selected;const categoryFilter=$('#costCategoryFilter');if(categoryFilter){const selectedCategory=categoryFilter.value,categories=[...new Set([...costCategories,...data.costs.map(c=>c.category).filter(Boolean)])];categoryFilter.innerHTML='<option value="">Tüm kategoriler</option>'+categories.map(category=>`<option>${category}</option>`).join('');categoryFilter.value=selectedCategory}}
async function removeStoredFiles(files){let failed=0;for(const file of files){try{await deleteStoredFile(file)}catch(error){console.error('Uzak dosya silinemedi:',error);failed++}}if(failed)toast(`${failed} uzak dosya silinemedi; depolama kaydını ayrıca kontrol edin.`)}
async function removeTaskRecord(t){if(!t)return;const linkedFiles=data.files.filter(file=>+file.taskId===+t.id);await removeStoredFiles(linkedFiles);addActivity(t.projectId,'Görev silindi',t.title,'task');data.tasks=data.tasks.filter(x=>x.id!==t.id);data.files=data.files.filter(file=>+file.taskId!==+t.id)}
document.addEventListener('click',async event=>{const button=event.target.closest?.('[data-detail-delete-task]');if(!button)return;event.preventDefault();event.stopImmediatePropagation();const task=data.tasks.find(item=>item.id===+button.dataset.detailDeleteTask);if(task&&confirm('Görev silinsin mi?')){await removeTaskRecord(task);save();renderProjectDetail()}},true)
function bindDeletes(){$$('[data-delete-project]').forEach(b=>b.onclick=async()=>{if(confirm('Proje ve bağlı kayıtları silmek istiyor musunuz?')){const id=+b.dataset.deleteProject,linkedFiles=data.files.filter(file=>+file.projectId===id);await removeStoredFiles(linkedFiles);data.projects=data.projects.filter(p=>p.id!==id);data.tasks=data.tasks.filter(t=>t.projectId!==id);data.costs=data.costs.filter(c=>c.projectId!==id);data.files=data.files.filter(x=>x.projectId!==id);data.suppliers=data.suppliers.filter(x=>x.projectId!==id);data.activities=data.activities.filter(x=>x.projectId!==id);save()}});$$('[data-delete-task]').forEach(b=>b.onclick=async()=>{const t=data.tasks.find(x=>x.id===+b.dataset.deleteTask);if(t){await removeTaskRecord(t);save()}});$$('[data-delete-cost]').forEach(b=>b.onclick=()=>{const c=data.costs.find(x=>x.id===+b.dataset.deleteCost);if(c){addActivity(c.projectId,'Maliyet silindi',`${c.description} — ${money(c.amount)}`,'cost');data.costs=data.costs.filter(x=>x.id!==c.id);save()}})}
let currentDetailId=null;
function addActivity(projectId,action,detail,kind='update'){if(!projectId)return;data.activities.unshift({id:Date.now()+Math.random(),projectId:+projectId,at:new Date().toISOString(),actor:currentUser?.name||'Sistem',action,detail,kind})}
let activityFilters={query:'',actor:'',kind:'',from:'',to:''};
function setupActivityFilters(projectId){const panel=$('#detailActivity .panel');if(!panel)return;const actors=[...new Set(data.activities.filter(a=>a.projectId===projectId).map(a=>a.actor))].sort();let tools=panel.querySelector('.activity-filters');if(!tools){tools=document.createElement('div');tools.className='activity-filters';panel.querySelector('.panel-head').insertAdjacentElement('afterend',tools)}tools.innerHTML=`<input type="search" data-activity-filter="query" placeholder="Hareketlerde ara..." value="${activityFilters.query}"><select data-activity-filter="actor"><option value="">Tüm kullanıcılar</option>${actors.map(x=>`<option ${activityFilters.actor===x?'selected':''}>${x}</option>`).join('')}</select><select data-activity-filter="kind"><option value="">Tüm işlemler</option><option value="task" ${activityFilters.kind==='task'?'selected':''}>Görev</option><option value="cost" ${activityFilters.kind==='cost'?'selected':''}>Maliyet</option><option value="file" ${activityFilters.kind==='file'?'selected':''}>Dosya</option><option value="supplier" ${activityFilters.kind==='supplier'?'selected':''}>Tedarikçi</option><option value="update" ${activityFilters.kind==='update'?'selected':''}>Güncelleme</option></select><label>Başlangıç <input type="date" data-activity-filter="from" value="${activityFilters.from}"></label><label>Bitiş <input type="date" data-activity-filter="to" value="${activityFilters.to}"></label><button class="secondary" id="clearActivityFilters">Temizle</button>`;tools.querySelectorAll('[data-activity-filter]').forEach(el=>el.oninput=()=>{activityFilters[el.dataset.activityFilter]=el.value;applyActivityFilters(projectId)});$('#clearActivityFilters').onclick=()=>{activityFilters={query:'',actor:'',kind:'',from:'',to:''};setupActivityFilters(projectId);applyActivityFilters(projectId)};applyActivityFilters(projectId)}
function applyActivityFilters(projectId){const q=activityFilters.query.toLocaleLowerCase('tr'),items=data.activities.filter(a=>a.projectId===projectId).filter(a=>(!activityFilters.actor||a.actor===activityFilters.actor)&&(!activityFilters.kind||a.kind===activityFilters.kind)&&(!activityFilters.from||a.at.slice(0,10)>=activityFilters.from)&&(!activityFilters.to||a.at.slice(0,10)<=activityFilters.to)&&(!q||`${a.action} ${a.detail} ${a.actor}`.toLocaleLowerCase('tr').includes(q))).sort((a,b)=>b.at.localeCompare(a.at));const timeline=$('#detailActivity .timeline');if(!timeline)return;timeline.innerHTML=items.map(a=>`<div class="timeline-item"><span class="timeline-icon ${a.kind}">${{task:'✓',cost:'₺',file:'▤',supplier:'◆',update:'↻'}[a.kind]||'•'}</span><div><div class="timeline-title"><strong>${a.action}</strong><time>${new Date(a.at).toLocaleString('tr-TR',{dateStyle:'medium',timeStyle:'short'})}</time></div><p>${a.detail}</p><small>${a.actor} tarafından</small></div></div>`).join('')||empty('Filtreye uygun hareket bulunamadı.');const count=$('#detailActivity .audit-count');if(count)count.textContent=`${items.length} hareket`}
function openProjectDetail(id){currentDetailId=+id;activityFilters={query:'',actor:'',kind:'',from:'',to:''};go('projectDetail');try{renderProjectDetail();if($('[data-detail-tab="activity"]')?.classList.contains('active'))setupActivityFilters(currentDetailId)}catch(error){console.error('Proje detayı açılırken hata oluştu:',error);toast('Proje açıldı; bazı detay alanları yüklenemedi.')}}
