function fileAsDataUrl(file){return new Promise((resolve,reject)=>{const reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.onerror=()=>reject(new Error(`${file.name} okunamadı.`));reader.readAsDataURL(file)})}
async function createFileRecord(projectId,file,taskId=null){if(file.size>15*1024*1024)throw new Error(`${file.name}: dosya sınırı 15 MB.`);const record={id:Date.now()+Math.random(),projectId:+projectId,taskId:taskId?+taskId:null,name:file.name,type:file.type||'application/octet-stream',size:file.size,uploadedAt:new Date().toISOString(),uploadedBy:currentUser.name};if(window.Proje360Backend?.enabled){const remote=await window.Proje360Backend.uploadProjectFile(projectId,file);record.id=remote.id||record.id;record.storagePath=remote.path;record.content=remote.url||'';return record}if(file.size>1500000)throw new Error(`${file.name}: 1,5 MB üzerindeki belgeler için canlı dosya alanını etkinleştirin.`);record.content=await fileAsDataUrl(file);return record}
async function deleteStoredFile(file){if(file?.storagePath&&window.Proje360Backend?.enabled&&window.Proje360Backend.deleteProjectFile)await window.Proje360Backend.deleteProjectFile(file.storagePath)}
async function uploadFiles(files){if(!currentUser)return;for(const file of files){try{toast(`${file.name} yükleniyor...`);const record=await createFileRecord(currentDetailId,file);data.files.push(record);addActivity(currentDetailId,'Dosya yüklendi',file.name,'file');save();renderProjectDetail()}catch(error){toast(`Yükleme başarısız: ${error.message}`)}}}
