let lastFileSaveSnapshot=JSON.stringify(data);
function dataFileSnapshot(){return JSON.stringify(data)}
function backupFileName(){const stamp=new Date().toISOString().slice(0,19).replaceAll(':','-').replace('T','_');return `PolPro-yedek-${stamp}.json`}
function dataFilePayload(){const exportData=cloneSeed(data);exportData.users.forEach(user=>delete user.password);return JSON.stringify({application:'PolPro',version:1,savedAt:new Date().toISOString(),data:exportData},null,2)}
async function writePickedFile(name,text,id){const handle=await window.showSaveFilePicker({id,startIn:'documents',suggestedName:name,types:[{description:'PolPro JSON veri dosyası',accept:{'application/json':['.json']}}]}),writable=await handle.createWritable();await writable.write(text);await writable.close();return handle}
function downloadDataFile(text,name){const blob=new Blob([text],{type:'application/json;charset=utf-8'}),link=document.createElement('a');link.href=URL.createObjectURL(blob);link.download=name;link.click();setTimeout(()=>URL.revokeObjectURL(link.href),1000)}
async function saveDataToFile(){
 const payload=dataFilePayload();
 try{
  if(window.showSaveFilePicker)await writePickedFile('polpro-veriler.json',payload,'polpro-main-save');
  else downloadDataFile(payload,'polpro-veriler.json');
  lastFileSaveSnapshot=dataFileSnapshot();toast('Ana veri dosyası güncellendi.');return true
 }catch(error){if(error?.name!=='AbortError')toast(`Dosya kaydedilemedi: ${error.message}`);return false}
}
async function backupDataToFile(){
 const payload=dataFilePayload(),name=backupFileName();
 try{
  if(window.showSaveFilePicker)await writePickedFile(name,payload,'polpro-backup-save');
  else downloadDataFile(payload,name);
  toast(`Tarihli yedek oluşturuldu: ${name}`);return true
 }catch(error){if(error?.name!=='AbortError')toast(`Yedek oluşturulamadı: ${error.message}`);return false}
}
async function applyLoadedData(text){
  const parsed=JSON.parse(text),loaded=parsed?.data||parsed;
  if(!loaded||!Array.isArray(loaded.projects)||!Array.isArray(loaded.tasks)||!Array.isArray(loaded.costs)||!Array.isArray(loaded.users))throw new Error('Geçerli bir PolPro veri dosyası değil.');
  const cloudMode=!!window.PolProCloud?.enabled;
  loaded.users.forEach(user=>{const existing=data.users.find(item=>item.email?.toLocaleLowerCase('tr')===user.email?.toLocaleLowerCase('tr'))||seed.users.find(item=>item.email?.toLocaleLowerCase('tr')===user.email?.toLocaleLowerCase('tr'));if(cloudMode)delete user.password;else if(!user.password&&existing?.password)user.password=existing.password;if(!['Yönetici','Kullanıcı','Görüntüleyici'].includes(user.role))user.role=existing?.role||'Kullanıcı'});
  if(!cloudMode&&!loaded.users.some(user=>user.active&&user.password))throw new Error('Veri dosyasında oturum açabilecek kullanıcı yok. Önce bir yönetici hesabı tanımlayın.');
  if(!confirm('Mevcut kayıtlar seçilen dosyadaki verilerle değiştirilsin mi?'))return false;
  data=loaded;localStorage.setItem('proje360-data',JSON.stringify(data));if(window.PolProCloud?.enabled)await window.PolProCloud.save(data);lastFileSaveSnapshot=dataFileSnapshot();location.reload();return true
}
async function loadPickedDataFile(id,errorLabel){try{if(window.showOpenFilePicker){const [handle]=await window.showOpenFilePicker({id,startIn:'documents',multiple:false,types:[{description:'PolPro JSON veri dosyası',accept:{'application/json':['.json']}}]});if(handle){const file=await handle.getFile();await applyLoadedData(await file.text())}}else $('#dataFileInput').click()}catch(error){if(error?.name!=='AbortError')toast(`${errorLabel}: ${error.message}`)}}
async function loadDataFromFile(){return loadPickedDataFile('polpro-main-open','Veri yüklenemedi')}
async function loadSelectedBackup(){return loadPickedDataFile('polpro-backup-open','Yedek yüklenemedi')}
$('#saveDataFile').onclick=saveDataToFile;
$('#backupDataFile').onclick=backupDataToFile;
$('#loadDataFile').onclick=loadDataFromFile;
$('#loadBackupFile').onclick=loadSelectedBackup;
$('#dataFileInput').onchange=async event=>{const file=event.target.files[0];if(!file)return;try{await applyLoadedData(await file.text())}catch(error){toast(`Veri yüklenemedi: ${error.message}`)}finally{event.target.value=''}};
