function openSystemExit(){if($('#entryDialog').open)$('#entryDialog').close();if(window.PolProCloud?.enabled){if(confirm('Oturum kapatılsın mı? Değişiklikleriniz otomatik olarak kaydedilir.'))void completeSystemExit();return}$('#exitDialog').showModal()}
