function initAuth(){const cloud=window.PolProCloud;if(cloud?.enabled&&cloud.profile){const profile=cloud.profile;startSession({id:profile.id,name:profile.full_name||profile.email||'PolPro Kullanıcısı',email:profile.email||'',role:profile.role||'Görüntüleyici',category:profile.category||'',active:profile.active!==false});return}const sessionId=sessionStorage.getItem('proje360-session'),user=data.users.find(u=>u.active&&String(u.id)===sessionId);if(user)startSession(user);else showLogin()}
function showLogin(){const screen=$('#loginScreen');screen.hidden=false;screen.setAttribute('aria-hidden','false');screen.classList.remove('hidden');document.body.classList.add('logged-out');$('#loginPassword').value='';$('#loginError').textContent='';setTimeout(()=>$('#loginEmail').focus(),50)}
function startSession(user){currentUser=user;sessionStorage.setItem('proje360-session',String(user.id));const screen=$('#loginScreen');screen.classList.add('hidden');screen.hidden=true;screen.setAttribute('aria-hidden','true');document.body.classList.remove('logged-out');$('#currentName').textContent=user.name;$('#currentRole').textContent=user.role;$('#roleChip').textContent=user.role;const initials=user.name.split(' ').map(x=>x[0]).slice(0,2).join('');$('#currentAvatar').textContent=initials;applyPermissions();go('dashboard')}
function applyPermissions(){if(!currentUser)return;decorateTaskFileCounts();const role=data.roles.includes(currentUser.role)?currentUser.role:'Görüntüleyici',isAdmin=role==='Yönetici',canEdit=role!=='Görüntüleyici',cloudMode=window.PolProCloud?.enabled,adminNav=$('[data-page="admin"]');if(adminNav)adminNav.hidden=!isAdmin;$$('[data-open],#quickAdd,.edit,[data-record-edit],.delete,.permission-create').forEach(x=>x.hidden=!canEdit);$$('[data-status],[data-detail-status]').forEach(x=>x.disabled=!canEdit);['#loadBackupFile','#backupDataFile'].forEach(selector=>{const button=$(selector);if(button)button.hidden=!isAdmin});const loadDataButton=$('#loadDataFile'),saveDataButton=$('#saveDataFile');if(loadDataButton)loadDataButton.hidden=cloudMode||!isAdmin;if(saveDataButton)saveDataButton.hidden=cloudMode;const activeAdmins=data.users.filter(user=>user.active&&user.role==='Yönetici').length;$$('[data-delete-user]').forEach(button=>{const target=data.users.find(user=>user.id===+button.dataset.deleteUser);if(target&&(target.id===currentUser.id||target.active&&target.role==='Yönetici'&&activeAdmins<=1))button.hidden=true});document.body.dataset.role=role}
